function longestConsecutive(nums) {
    const arr = Array.isArray(nums) ? nums.filter((x) => !Number.isNaN(x)) : [];
    if (arr.length === 0) return 0;
    const set = new Set(arr);
    let best = 0;
    for (const x of set) {
        if (!set.has(x - 1)) {
            let y = x;
            while (set.has(y + 1)) y += 1;
            best = Math.max(best, y - x + 1);
        }
    }
    return best;
}

